// The dungeon's own face — the parting iron gate, rendered once and
// embedded so the Worker serves its avatar itself (no third-party image host).
// Regenerate with promo/capture/_pfp.mjs if the seal ever changes.
export const ICON_PNG_B64 =
  "";

export function iconBytes(): Uint8Array {
  const bin = atob(ICON_PNG_B64);
  const out = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) out[i] = bin.charCodeAt(i);
  return out;
}
